# XOR 解密脚本

def xor_decrypt(data, key):
    """单字节或多字节 XOR 解密"""
    if isinstance(key, int):
        key = bytes([key])
    result = []
    for i, b in enumerate(data):
        result.append(b ^ key[i % len(key)])
    return bytes(result)

# 常见 XOR 密钥猜测
def guess_xor_key(ciphertext):
    """通过频率分析猜测密钥"""
    for key in range(256):
        decrypted = xor_decrypt(ciphertext, key)
        if b'flag' in decrypted.lower() or b'ctf' in decrypted.lower():
            return key, decrypted
    return None, None

# 已知明文攻击
def known_plaintext_attack(ciphertext, known_plaintext):
    """已知明文恢复密钥"""
    key = []
    for i, c in enumerate(known_plaintext):
        key.append(ciphertext[i] ^ ord(c))
    return bytes(key)

